import { z } from "zod";

import { bounds, config } from "../../config/index.js";
import {
  boundedInt,
  enforceActivePayload,
  glyphSchema,
  nonEmptyString,
} from "../common.js";
import { EffectBundleSchema, type EffectBundle } from "../vocab/index.js";
import {
  DepthBandSchema,
  EntityNameSchema,
  ItemCategorySchema,
  type DepthBand,
  type ItemCategory,
} from "./common.js";

export const ItemValueSchema = z
  .strictObject({
    band: DepthBandSchema,
    coin: z.number().int(),
  })
  .superRefine((value, ctx) => {
    const valueBounds = config.itemsEconomy.valueBandsCoin[value.band];

    if (value.coin < valueBounds.min) {
      ctx.addIssue({
        code: "custom",
        path: ["coin"],
        message: `${value.band} item value must be at least ${valueBounds.min}`,
      });
    }

    if (value.coin > valueBounds.max) {
      ctx.addIssue({
        code: "custom",
        path: ["coin"],
        message: `${value.band} item value must be at most ${valueBounds.max}`,
      });
    }
  });

export const WeaponItemPayloadSchema = z.strictObject({
  attackBonus: boundedInt(bounds.itemsEconomy.weaponAtkBonus),
});

export const ArmorItemPayloadSchema = z.strictObject({
  defenseBonus: boundedInt(bounds.itemsEconomy.armorDefBonus),
});

export const CharmItemPayloadSchema = z
  .strictObject({
    passive: EffectBundleSchema,
  })
  .superRefine((payload, ctx) => {
    enforceCharmPassive(payload.passive, ctx);
  });

export const DraughtItemPayloadSchema = z.strictObject({
  effect: EffectBundleSchema,
});

export const NoteItemPayloadSchema = z.strictObject({
  effect: EffectBundleSchema,
});

export const ThrowableItemPayloadSchema = z.strictObject({
  effect: EffectBundleSchema,
});

export const FoodItemPayloadSchema = z.strictObject({
  effect: EffectBundleSchema,
});

export const ToolItemPayloadSchema = z.strictObject({
  effect: EffectBundleSchema,
});

export const KeyItemPayloadSchema = z.strictObject({
  questHookId: nonEmptyString.nullable(),
});

export const CoinItemPayloadSchema = z.strictObject({});

const ITEM_PAYLOAD_KEYS = [
  "weapon",
  "armor",
  "charm",
  "draught",
  "note",
  "throwable",
  "food",
  "tool",
  "keyItem",
  "coin",
] as const;

const ITEM_PAYLOAD_FIELD_BY_KIND = {
  weapon: "weapon",
  armor: "armor",
  charm: "charm",
  draught: "draught",
  note: "note",
  throwable: "throwable",
  food: "food",
  tool: "tool",
  key_item: "keyItem",
  coin: "coin",
} as const satisfies Record<ItemCategory, (typeof ITEM_PAYLOAD_KEYS)[number]>;

// Provider-facing: required nullable payload fields avoid a root union.
export const ItemDefinitionSchema = z
  .strictObject({
    id: nonEmptyString,
    name: EntityNameSchema,
    glyph: glyphSchema,
    kind: ItemCategorySchema,
    value: ItemValueSchema,
    weapon: WeaponItemPayloadSchema.nullable(),
    armor: ArmorItemPayloadSchema.nullable(),
    charm: CharmItemPayloadSchema.nullable(),
    draught: DraughtItemPayloadSchema.nullable(),
    note: NoteItemPayloadSchema.nullable(),
    throwable: ThrowableItemPayloadSchema.nullable(),
    food: FoodItemPayloadSchema.nullable(),
    tool: ToolItemPayloadSchema.nullable(),
    keyItem: KeyItemPayloadSchema.nullable(),
    coin: CoinItemPayloadSchema.nullable(),
  })
  .superRefine((item, ctx) => {
    enforceActivePayload(
      item,
      ctx,
      ITEM_PAYLOAD_KEYS,
      ITEM_PAYLOAD_FIELD_BY_KIND[item.kind],
    );
  });

export type ItemDefinition = z.infer<typeof ItemDefinitionSchema>;

const enforceCharmPassive = (
  passive: EffectBundle,
  ctx: z.RefinementCtx,
): void => {
  if (passive.effects.length !== bounds.itemsEconomy.charmEquipPassiveEffects) {
    ctx.addIssue({
      code: "custom",
      path: ["passive", "effects"],
      message: `charm passive must contain exactly ${bounds.itemsEconomy.charmEquipPassiveEffects} effect`,
    });
  }

  if (passive.trigger.kind !== "equip_passive") {
    ctx.addIssue({
      code: "custom",
      path: ["passive", "trigger", "kind"],
      message: "charm passive trigger must be equip_passive",
    });
  }
};

export const itemValueBoundsForBand = (band: DepthBand) =>
  config.itemsEconomy.valueBandsCoin[band];

import type { GameConfig } from "../../config/index.js";
import type {
  DepthBand,
  EnemyDefinition,
  ItemDefinition,
  NpcDefinition,
  QuestDefinition,
  TrapDefinition,
} from "../../schemas/entities/index.js";
import type {
  ENGINE_VERSION,
  PROTOCOL_VERSION,
} from "../../schemas/protocol.js";
import type { StatusApplication } from "../../schemas/vocab/index.js";

export type SerializablePrimitive = string | number | boolean | null;

export type SerializableValue =
  | SerializablePrimitive
  | readonly SerializableValue[]
  | { readonly [key: string]: SerializableValue };

export type SerializableRecord = {
  readonly [key: string]: SerializableValue;
};

export const ACTIVE_TERMINAL_STATUS = "ACTIVE" as const;

export type ConfiguredTerminalStatus =
  GameConfig["runStructure"]["terminalStates"][keyof GameConfig["runStructure"]["terminalStates"]];

export type TerminalStatus =
  | typeof ACTIVE_TERMINAL_STATUS
  | ConfiguredTerminalStatus;

export interface VersionStamp {
  readonly protocolVersion: typeof PROTOCOL_VERSION;
  readonly engineVersion: typeof ENGINE_VERSION;
}

export interface RunMeta {
  readonly runId: string;
  readonly seed: string;
  readonly depth: number;
  readonly band: DepthBand;
  readonly turn: number;
  readonly terminalStatus: TerminalStatus;
}

export interface Position {
  readonly x: number;
  readonly y: number;
}

export interface FloorGeometrySlot {
  readonly refId: string;
  /*
   * PHASE-07A contract: the map module owns this payload's concrete shape.
   * PHASE-06 only requires a stable, serializable geometry reference by id.
   */
  readonly opaque: SerializableRecord | null;
}

export interface FloorState {
  readonly floorId: string;
  readonly depth: number;
  readonly band: DepthBand;
  readonly geometry: FloorGeometrySlot;
}

export interface PlayerItemStack {
  readonly itemInstanceId: string;
  readonly definition: ItemDefinition;
  readonly quantity: number;
  readonly identified: boolean;
}

export type InventorySlot = PlayerItemStack | null;

export interface EquipmentState {
  readonly weapon: PlayerItemStack | null;
  readonly armor: PlayerItemStack | null;
  readonly charms: readonly (PlayerItemStack | null)[];
}

export interface PlayerState {
  readonly hp: {
    readonly current: number;
    readonly max: number;
  };
  readonly level: number;
  readonly xp: number;
  readonly fullness: {
    readonly current: number;
    readonly max: number;
  };
  readonly position: Position;
  readonly inventory: readonly InventorySlot[];
  readonly equipment: EquipmentState;
  readonly statuses: readonly StatusApplication[];
}

export type EntityKind = "enemy" | "npc" | "item" | "trap";

export type EntityIdCounters = {
  readonly [Kind in EntityKind]: number;
};

export type EntityId = `${EntityKind}#${number}`;

export interface EntityRuntimeFields {
  readonly id: EntityId;
  readonly position: Position;
  readonly currentHP: number | null;
  readonly statuses: readonly StatusApplication[];
  readonly behaviorRuntime: SerializableRecord;
}

export interface EnemyEntityInstance extends EntityRuntimeFields {
  readonly kind: "enemy";
  readonly definition: EnemyDefinition;
  readonly currentHP: number;
}

export interface NpcEntityInstance extends EntityRuntimeFields {
  readonly kind: "npc";
  readonly definition: NpcDefinition;
  readonly dialogueRuntime: SerializableRecord;
}

export interface GroundItemEntityInstance extends EntityRuntimeFields {
  readonly kind: "item";
  readonly definition: ItemDefinition;
  readonly currentHP: null;
  readonly quantity: number;
  readonly identified: boolean;
}

export interface TrapEntityInstance extends EntityRuntimeFields {
  readonly kind: "trap";
  readonly definition: TrapDefinition;
  readonly currentHP: null;
  readonly armed: boolean;
}

export type EntityInstance =
  | EnemyEntityInstance
  | NpcEntityInstance
  | GroundItemEntityInstance
  | TrapEntityInstance;

export type EntityMap = {
  readonly [id: string]: EntityInstance;
};

export type QuestRuntimeStatus = "available" | "active" | "completed" | "failed";

export interface QuestRuntime {
  readonly definition: QuestDefinition;
  readonly status: QuestRuntimeStatus;
  readonly progress: SerializableRecord;
}

export interface QuestState {
  readonly quests: {
    readonly [id: string]: QuestRuntime;
  };
  readonly activeQuestIds: readonly string[];
  readonly completedQuestIds: readonly string[];
  readonly failedQuestIds: readonly string[];
}

/*
 * Log extension pattern:
 * later engine systems add event types by declaration-merging this interface.
 * The runtime serializer validates the event envelope and serializable data.
 */
export interface EngineLogEventDataByType {
  readonly state_created: {
    readonly runId: string;
    readonly seed: string;
    readonly depth: number;
    readonly band: DepthBand;
  };
  readonly state_serialized: {
    readonly format: "stable-json";
  };
  readonly state_deserialized: {
    readonly format: "stable-json";
  };
}

export type EngineLogEventType = Extract<
  keyof EngineLogEventDataByType,
  string
>;

export type EngineLogEvent = {
  readonly [Type in EngineLogEventType]: {
    readonly turn: number;
    readonly type: Type;
    readonly data: EngineLogEventDataByType[Type];
  };
}[EngineLogEventType];

export interface RngStreamCursor {
  readonly streamId: string;
  readonly seed: string;
  readonly parentStreamId: string | null;
  readonly draws: number;
}

export interface RngState {
  readonly rootSeed: string;
  readonly streams: {
    readonly [streamId: string]: RngStreamCursor;
  };
}

export interface IdState {

import type {
  EntityId,
  EntityInstance,
  GameState,
  InventorySlot,
  Position,
  SerializableRecord,
} from "../state/index.js";
import {
  chebyshevDistance,
  getTile,
  inBounds,
  isWalkableTile,
  Terrain,
  type TileGrid,
} from "../map/index.js";

export const MOVE_DIRECTIONS = [
  { direction: "northwest", offset: { x: -1, y: -1 } },
  { direction: "north", offset: { x: 0, y: -1 } },
  { direction: "northeast", offset: { x: 1, y: -1 } },
  { direction: "west", offset: { x: -1, y: 0 } },
  { direction: "east", offset: { x: 1, y: 0 } },
  { direction: "southwest", offset: { x: -1, y: 1 } },
  { direction: "south", offset: { x: 0, y: 1 } },
  { direction: "southeast", offset: { x: 1, y: 1 } },
] as const;

export type MoveDirection = (typeof MOVE_DIRECTIONS)[number]["direction"];

export type ActionTarget =
  | {
      readonly kind: "self";
    }
  | {
      readonly kind: "entity";
      readonly entityId: EntityId;
    }
  | {
      readonly kind: "cell";
      readonly cell: Position;
    };

export type MoveAction = {
  readonly kind: "move";
  readonly direction: MoveDirection;
};

export type AttackAction = {
  readonly kind: "attack";
  readonly targetId: EntityId;
};

export type UseItemAction = {
  readonly kind: "use_item";
  readonly itemId: string;
  readonly target?: ActionTarget;
};

export type PickupAction = {
  readonly kind: "pickup";
};

export type TalkAction = {
  readonly kind: "talk";
  readonly npcId: EntityId;
};

export type WaitAction = {
  readonly kind: "wait";
};

export type DescendAction = {
  readonly kind: "descend";
};

export type InspectAction = {
  readonly kind: "inspect";
  readonly cell: Position;
};

export type AbortAction = {
  readonly kind: "abort";
};

export type PlayerAction =
  | MoveAction
  | AttackAction
  | UseItemAction
  | PickupAction
  | TalkAction
  | WaitAction
  | DescendAction
  | InspectAction
  | AbortAction;

export type LegalActionResult = {
  readonly status: "legal";
};

export type IllegalActionResult = {
  readonly status: "illegal";
  readonly reason: string;
};

export type ActionLegality = LegalActionResult | IllegalActionResult;

export const LEGAL_ACTION = { status: "legal" } as const satisfies ActionLegality;

export const isActionLegal = (
  result: ActionLegality,
): result is LegalActionResult => result.status === "legal";

export const checkActionLegality = (
  state: GameState,
  action: PlayerAction,
): ActionLegality => {
  if (state.run.terminalStatus !== "ACTIVE") {
    return illegal(`run is terminal (${state.run.terminalStatus})`);
  }

  switch (action.kind) {
    case "move":
      return checkMoveAction(state, action);
    case "attack":
      return checkAttackAction(state, action);
    case "use_item":
      return checkUseItemAction(state, action);
    case "pickup":
      return checkPickupAction(state);
    case "talk":
      return checkTalkAction(state, action);
    case "wait":
      return LEGAL_ACTION;
    case "descend":
      return checkDescendAction(state);
    case "inspect":
      return checkInspectAction(state, action);
    case "abort":
      return LEGAL_ACTION;
  }
};

export const getAvailableActions = (state: GameState): readonly PlayerAction[] => {
  if (state.run.terminalStatus !== "ACTIVE") {
    return [];
  }

  const actions: PlayerAction[] = [];

  for (const { direction } of MOVE_DIRECTIONS) {
    const action = { kind: "move", direction } as const;
    pushIfLegal(actions, state, action);
  }

  for (const entity of sortedEntities(state)) {
    if (entity.kind === "enemy") {
      pushIfLegal(actions, state, {
        kind: "attack",
        targetId: entity.id,
      });
    }
  }

  for (const item of carriedItems(state.player.inventory)) {
    pushIfLegal(actions, state, {
      kind: "use_item",
      itemId: item.itemInstanceId,
    });
  }

  pushIfLegal(actions, state, { kind: "pickup" });

  for (const entity of sortedEntities(state)) {
    if (entity.kind === "npc") {
      pushIfLegal(actions, state, {
        kind: "talk",
        npcId: entity.id,
      });
    }
  }

  pushIfLegal(actions, state, { kind: "wait" });
  pushIfLegal(actions, state, { kind: "descend" });
  actions.push(...availableInspectActions(state));
  pushIfLegal(actions, state, { kind: "abort" });

  return actions;
};

export const destinationForMove = (
  origin: Position,
  direction: MoveDirection,
): Position => {
  const offset = offsetForDirection(direction);

  return {
    x: origin.x + offset.x,
    y: origin.y + offset.y,
  };
};

export const gridFromState = (state: GameState): TileGrid | null => {
  const opaque = state.floor.geometry.opaque;

  if (!isTileGridRecord(opaque)) {
    return null;
  }

  return opaque as unknown as TileGrid;
};

const checkMoveAction = (
  state: GameState,
  action: MoveAction,
): ActionLegality => {
  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  const destination = destinationForMove(state.player.position, action.direction);

  if (!inBounds(grid, destination)) {
    return illegal(
      `move ${action.direction} leaves the map at (${destination.x}, ${destination.y})`,
    );
  }

  const tile = getTile(grid, destination);

  if (!isWalkableTile(tile)) {
    return illegal(`terrain ${tile.terrain} blocks movement`);
  }

  return LEGAL_ACTION;
};

const checkAttackAction = (
  state: GameState,
  action: AttackAction,
): ActionLegality => {
  const target = state.entities[action.targetId];

  if (target === undefined) {
    return illegal(`attack target ${action.targetId} does not exist`);
  }

  if (target.kind !== "enemy") {
    return illegal(`attack target ${action.targetId} is not an enemy`);
  }

  if (!isAdjacentToPlayer(state, target.position)) {
    return illegal(`attack target ${action.targetId} is not adjacent`);
  }

  return LEGAL_ACTION;
};

